import{o,c as e,b as d}from"./vue-75de9efb.js";const t={class:"markdown-body"},c=[d('<h1 id="%E5%BC%80%E5%A7%8B" tabindex="-1">开始</h1><p>欢迎使用 BiluoUI</p><h2 id="%E4%BB%8B%E7%BB%8D" tabindex="-1">介绍</h2><p>这是一个模仿element ui写的ui组件。用以练手和学习，能力有限，很多重要的功能并没有实现，已经实现的功能有一部分并没有完全按照element的功能来。</p><p>以下是使用的技术栈 <strong>vue3, typescript, vite, vite-plugin-md, tailwindcss, scss</strong></p><h2 id="%E5%B7%B2%E7%BB%8F%E5%AE%9E%E7%8E%B0%E7%BB%84%E4%BB%B6" tabindex="-1">已经实现组件</h2><p><strong>基础组件:</strong><code>button 按钮</code> <code>layout 布局</code> <code>container 容器</code> <code>icon 图标</code><br><strong>form表单组件:</strong><code>radio 单选框</code> <code>switch 开关</code> <code>input 输入框</code><br><strong>data数据展示:</strong><code>badge 角标</code> <br><strong>反馈组件:</strong><code>message 消息提示</code> <code>message box 消息弹出框</code> <code>drawer 抽屉</code> <br></p><h2 id="%E7%89%88%E6%9C%AC" tabindex="-1">版本</h2><blockquote><p><strong>版本：1.0.0</strong><br> 更新内容：首次发布</p></blockquote>',9)],s={setup:(d,{expose:s})=>(s({frontmatter:{}}),(d,s)=>(o(),e("div",t,c)))};export{s as default};
